189→            progressBar.value = 0;
190→            document.getElementById('pipeline-progress').hidden = false;
191→            document.getElementById('pipeline-confirm').hidden = true;
192→            appendLog(`Sending messages to ${msg.total} candidates...`);
193→            break;
194→
195→        case 'send_progress':
196→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
197→            progressBar.value = msg.sent + msg.failed;
198→            progressBar.max = msg.total;
199→            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
200→            if (msg.status === 'sent') {
201→                appendLog(`Sent to ${msg.current}`, 'ok');
202→            } else if (msg.status === 'failed') {
203→                appendLog(`Failed: ${msg.current} — ${msg.error || 'unknown'}`, 'err');
204→            } else if (msg.status === 'skipped') {
205→                appendLog(`Skipped: ${msg.current}`, 'warn');
206→            } else {
207→                appendLog(`${msg.current} (${msg.sent}/${msg.total})`);
208→            }
209→            break;
210→
211→        case 'completed':
212→            appendLog('Pipeline completed', 'ok');
213→            showPipelineResults(msg.result);
214→            break;
215→
216→        default:
